"use client";

import { Languages } from "lucide-react";
import type { Locale } from "@/data/invitation";

interface LanguageSwitchProps {
  locale: Locale;
  onToggle: () => void;
  label: string;
}

export function LanguageSwitch({ locale, onToggle, label }: LanguageSwitchProps) {
  return (
    <button
      type="button"
      onClick={onToggle}
      className="inline-flex items-center gap-2 rounded-full border border-white/70 bg-white/85 px-4 py-3 text-sm font-semibold text-slate-700 shadow-lg shadow-sky-200/35 backdrop-blur-xl transition hover:-translate-y-0.5 hover:bg-white"
      aria-label={label}
    >
      <Languages className="h-4 w-4 text-sky-700" />
      <span>{locale === "es" ? "ES" : "EN"}</span>
      <span className="text-slate-400">/</span>
      <span className="text-slate-500">{locale === "es" ? "EN" : "ES"}</span>
    </button>
  );
}
