"use client";

import { useCallback, useEffect, useRef, useState } from "react";

type MusicState = "idle" | "playing" | "paused";

export function useBackgroundMusic() {
  const audioContextRef = useRef<AudioContext | null>(null);
  const oscillatorsRef = useRef<OscillatorNode[]>([]);
  const gainRef = useRef<GainNode | null>(null);
  const [state, setState] = useState<MusicState>("idle");

  const stop = useCallback(() => {
    oscillatorsRef.current.forEach((oscillator) => {
      try {
        oscillator.stop();
      } catch {
        // ignore double-stop edge cases
      }
      oscillator.disconnect();
    });
    oscillatorsRef.current = [];

    gainRef.current?.disconnect();
    gainRef.current = null;

    audioContextRef.current?.close().catch(() => undefined);
    audioContextRef.current = null;
    setState("paused");
  }, []);

  const play = useCallback(async () => {
    if (typeof window === "undefined") {
      return;
    }

    if (audioContextRef.current && state === "playing") {
      return;
    }

    const audioContext = new window.AudioContext();
    audioContextRef.current = audioContext;

    const gainNode = audioContext.createGain();
    gainNode.gain.value = 0.05;
    gainNode.connect(audioContext.destination);
    gainRef.current = gainNode;

    const notes = [261.63, 329.63, 392, 523.25];
    notes.forEach((frequency, index) => {
      const oscillator = audioContext.createOscillator();
      oscillator.type = "sine";
      oscillator.frequency.value = frequency;
      oscillator.connect(gainNode);
      oscillator.start(audioContext.currentTime + index * 0.35);
      oscillator.stop(audioContext.currentTime + 3.2 + index * 0.35);
      oscillatorsRef.current.push(oscillator);
    });

    const ambient = audioContext.createOscillator();
    ambient.type = "triangle";
    ambient.frequency.value = 196;
    ambient.connect(gainNode);
    ambient.start();
    oscillatorsRef.current.push(ambient);

    setState("playing");
  }, [state]);

  useEffect(() => {
    return () => {
      stop();
    };
  }, [stop]);

  return {
    isPlaying: state === "playing",
    play,
    stop
  };
}
